#include "st7735_tft.h"
#include <SPI.h>
#include <Adafruit_GFX.h>
static Adafruit_ST7735 tft(5,16,17);
void st7735_setup(){tft.initR(INITR_BLACKTAB);tft.setRotation(1);tft.fillScreen(ST77XX_BLACK);Serial.println("[st7735] OK 160x128");}
void st7735_clear(uint16_t c){tft.fillScreen(c);}
void st7735_text(int x,int y,const char*t,uint16_t c,int s){tft.setCursor(x,y);tft.setTextColor(c);tft.setTextSize(s);tft.print(t);}
void st7735_rect(int x,int y,int w,int h,uint16_t c){tft.drawRect(x,y,w,h,c);}
